const sourceCode = "# Button\n\n주요 액션과 보조 액션에 사용하는 버튼 컴포넌트입니다.\n\n## 예시\n\n<ComponentPreview>\n  <ButtonDemo />\n</ComponentPreview>\n\n## Props\n\n| Prop      | Type                                                                 | Default   | 설명 |\n| --------- | -------------------------------------------------------------------- | --------- | ---- |\n| variant   | `\"solid\"` \\| `\"outline\"` \\| `\"ghost\"` \\| `\"weak\"`                    | `\"solid\"` | 스타일 변형 |\n| size      | `\"small\"` \\| `\"medium\"` \\| `\"large\"` \\| `\"xlarge\"`                   | `\"medium\"` | 크기 |\n| intent    | `\"primary\"` \\| `\"secondary\"` \\| `\"success\"` \\| `\"warning\"` \\| `\"danger\"` \\| `\"neutral\"` | `\"primary\"` | 색상 의도 |\n| rounded   | `\"small\"` \\| `\"medium\"` \\| `\"large\"`                                  | `\"medium\"` | 모서리 반경 |\n| fullWidth | `boolean`                                                            | `false`   | 전체 너비 |\n| disabled  | `boolean`                                                            | `false`   | 비활성화 |\n\n`<button>`의 표준 HTML 속성도 지원합니다.\n\n## 코드\n\n```tsx\nimport { Button } from \"pine-design-system\";\n\n<Button variant=\"solid\" intent=\"primary\" size=\"large\">\n  Submit\n</Button>\n```";
