const sourceCode = "# TextField\n\n텍스트 입력 필드입니다. 단일 줄 input과 textarea(multiline)를 지원합니다.\n\n## 예시\n\n<ComponentPreview>\n  <TextFieldDemo />\n</ComponentPreview>\n\n## Props\n\n| Prop        | Type     | Default   | 설명 |\n| ----------- | -------- | --------- | ---- |\n| label       | `string` | —         | 레이블 |\n| helperText  | `string` | —         | 하단 도움말/에러 메시지 |\n| placeholder | `string` | —         | 플레이스홀더 |\n| size        | `\"small\"` \\| `\"medium\"` \\| `\"large\"` \\| `\"xlarge\"` | `\"medium\"` | 크기 |\n| rounded     | `\"small\"` \\| `\"medium\"` \\| `\"large\"` | `\"medium\"` | 모서리 반경 |\n| variant     | `\"outline\"` \\| `\"filled\"` | `\"outline\"` | 스타일 변형 |\n| status      | `\"default\"` \\| `\"error\"` \\| `\"success\"` | `\"default\"` | 검증 상태 |\n| fullWidth   | `boolean` | `false`   | 전체 너비 |\n| multiline   | `boolean` | `false`   | textarea 모드 |\n| rows        | `number`  | 3 (multiline 시) | textarea 행 수 |\n| disabled    | `boolean` | `false`   | 비활성화 |\n\n`<input>` / `<textarea>`의 표준 속성(value, onChange, name, required 등)도 지원합니다.\n\n## 코드\n\n```tsx\nimport { TextField } from \"pine-design-system\";\n\n<TextField\n  label=\"Email\"\n  type=\"email\"\n  placeholder=\"you@example.com\"\n  required\n/>\n<TextField label=\"Bio\" multiline rows={4} />\n```";
